func (g *grantDBADapter) GetGrant(ctx context.Context, grantID models.NamespacedID) (grant.Grant, error) {
	ent, err := g.db.Grant.Query().Where(db_grant.ID(grantID.ID), db_grant.Namespace(grantID.Namespace)).Only(ctx)
	if err != nil {
		if db.IsNotFound(err) {
			return grant.Grant{}, &credit.GrantNotFoundError{GrantID: grantID.ID}
		}
		return grant.Grant{}, err
	}
	return mapGrantEntity(ent), nil
}

func (s *service) GetLatestValidAt(ctx context.Context, owner models.NamespacedID, at time.Time) (Snapshot, error) {
	res, err := s.Repo.GetLatestValidAt(ctx, owner, at)
	if err != nil { return Snapshot{}, err }
	if res.Usage.IsZero() {
		periodStart, err := s.OwnerConnector.GetUsagePeriodStartAt(ctx, owner, res.At)
		if err != nil { return Snapshot{}, err }
		usage, err := s.UsageQuerier.QueryUsage(ctx, owner, timeutil.ClosedPeriod{From: periodStart, To: res.At})
		if err != nil { return Snapshot{}, err }
		res.Usage = SnapshottedUsage{Usage: usage, Since: periodStart}
	}
	return res, nil
}

for idx, period := range timeline.GetClosedPeriods() {
	relevantGrants := e.filterRelevantGrants(params.Grants, snapshot.Balances, period)
	runRes, err := e.runBetweenResets(ctx, inbetweenRunParams{
		Grants: relevantGrants, Until: period.To, StartingSnapshot: snapshot, Meter: params.Meter,
		PeriodEndRecurrenceBoundaryBehavior: lo.Ternary(idx == len(timeline.GetClosedPeriods())-1, timeutil.Inclusive, timeutil.Exclusive),
	})
	if err != nil { return RunResult{}, err }
	snapshot = runRes.Snapshot
	historySegments = append(historySegments, runRes.History.Segments()...)
	if idx != len(timeline.GetClosedPeriods())-1 {
		snapshot, _ = e.reset(relevantGrants, runRes.Snapshot, params.ResetBehavior, period.To)
		historySegments[len(historySegments)-1].TerminationReasons.UsageReset = true
	}
}

func (g Grant) GetEffectivePeriod() timeutil.StartBoundedPeriod {
	p := timeutil.StartBoundedPeriod{From: g.EffectiveAt, To: g.ExpiresAt}
	if g.DeletedAt != nil {
		if p.To == nil || g.DeletedAt.Before(*p.To) { p.To = g.DeletedAt }
	}
	if g.VoidedAt != nil {
		if p.To == nil || g.VoidedAt.Before(*p.To) { p.To = g.VoidedAt }
	}
	if p.To != nil && p.To.Before(p.From) { p.To = &p.From }
	return p
}
